from fastapi import Depends, FastAPI, HTTPException, status
from fastapi.security import HTTPAuthorizationCredentials, HTTPBearer

app = FastAPI()
_bearer = HTTPBearer()


def current_user(
    creds: HTTPAuthorizationCredentials = Depends(_bearer),
) -> dict:
    try:
        return verify_token(creds.credentials)
    except (PyJWTError, ValueError) as exc:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail=str(exc),
            headers={"WWW-Authenticate": "Bearer"},
        ) from exc


@app.post("/runs")
def start_run(body: dict, user: dict = Depends(current_user)):
    # user is the verified JWT payload dict
    tenant_id = user["tenant_id"]
    if "agent:run" not in user.get("scope", "").split():
        raise HTTPException(403, "scope agent:run required")
    return run_agent(body, tenant_id=tenant_id)

// Node.js — npm install jsonwebtoken
const jwt = require('jsonwebtoken');

// --- Issue (server side, kept for illustration) ---
const token = jwt.sign(
  { sub: 'user-42', tenant_id: 'acme', scope: 'agent:run' },
  process.env.JWT_SECRET,
  { algorithm: 'HS256', expiresIn: '1h', audience: 'agent-api', issuer: 'https://auth.example.com' }
);

// --- Client: attach to fetch ---
async function startRun(prompt) {
  const res = await fetch('https://api.example.com/runs', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ prompt }),
  });
  if (res.status === 401) throw new Error('Token expired or invalid');
  return res.json();
}

// --- Verify (server side) ---
function verifyToken(token) {
  return jwt.verify(token, process.env.JWT_SECRET, {
    algorithms: ['HS256'],
    audience: 'agent-api',
    issuer: 'https://auth.example.com',
  });
}

